import "../../SilksMarketplaceStorage.sol";

// Struct for a marketplace listing type.
    struct ListingType {
        address contractAddress;
        string description;
        uint256 ercStandard;
        bool active;
        bool valid;
    }

// Struct for a marketplace listing.
    struct Listing {
        bytes32 listingId;       // Unique identifier for the listing.
        address listingAddress;  // Address for listing's contract.
        address seller;          // Address of the seller.
        address buyer;           // Address of the buyer.
        uint256 tokenId;         // Token ID associated with the listing.
        uint256 numListed;        // Quantity Of token listed
        uint256 pricePer;        // Price per token of the listing.
        uint256 royaltyBasePoints;      // Royalty percentage.
        bool active;             // Status of the listing (active/inactive).
        bool valid;              // Validity of the listing.
    }

bytes32 constant LISTING_ADMIN_ROLE = keccak256("silks.contracts.roles.ListingAdminRole");
bytes32 constant LISTINGS_PAUSED = keccak256('silks.contracts.paused.Listings');

    error InvalidListing(bytes32 listingId);
    error ListingAlreadyPurchased(bytes32 listingId);
    error InvalidListingType(address listingAddress);
    error InactiveListingType(address listingAddress);
    error UnsupportedERCStandard(uint256 ercStandard);
    error CreateListingFailed(string reason, bytes32 listingId, address listingAddress, address seller, address buyer, uint256 tokenId, uint256 numListed, uint256 pricePer, uint256 royaltyBasePoints, bool active);

library ListingStorage {
    using EnumerableSet for EnumerableSet.UintSet;
    using EnumerableSet for EnumerableSet.Bytes32Set;

    // Storage slot for the layout.
    bytes32 internal constant STORAGE_SLOT = keccak256('silks.contracts.storage.SilksMarketplaceListings');

    // Struct for the layout of the marketplace.
    struct Layout {
        mapping(address => ListingType) listingTypes;

        mapping(bytes32 => Listing) listings;
        mapping(address => EnumerableSet.Bytes32Set) purchasesByAddress;
        mapping(address => EnumerableSet.UintSet) tokensListedByListingAddress;
        EnumerableSet.Bytes32Set activeListings;
        EnumerableSet.UintSet supportedERCStandards;
    }

    // Function to retrieve the layout.
    function layout()
    internal
    pure
    returns (
        Layout storage _l
    ) {
        bytes32 slot = STORAGE_SLOT;
        assembly {
            _l.slot := slot
        }
    }

    /**
     * @dev Internal function to verify if an asset can be sold.
     * @param _listingAddress Contract address for the listing.
     * @param _addressToCheck The address to check for ownership and approval.
     * @param _tokenId The token ID of the asset.
     */
    function verifyAssetCanBeSold(
        address _listingAddress,
        address _addressToCheck,
        uint256 _tokenId,
        uint256 _quantity
    )
    internal
    view
    {
        // Access marketplace layout
        ListingType storage listingType = layout().listingTypes[_listingAddress];

        // Validate listing type and address
        if (!listingType.valid) {
            revert InvalidListingType(_listingAddress);
        }

        // Validate token ownership and approval
        if (listingType.ercStandard == 721){
            ERC721Base assetContract = ERC721Base(listingType.contractAddress);
            if (assetContract.ownerOf(_tokenId) != _addressToCheck) {
                revert NotTokenOwner(_listingAddress, _addressToCheck, _tokenId);
            }
            if (!assetContract.isApprovedForAll(_addressToCheck, address(this))) {
                revert ApprovalNotSetForMarketplace();
            }
        } else if (listingType.ercStandard == 1155){
            ERC1155Base assetContract = ERC1155Base(listingType.contractAddress);
            uint256 numOwned = assetContract.balanceOf(_addressToCheck, _tokenId);
            if (numOwned == 0){
                revert NotTokenOwner(_listingAddress, msg.sender, _tokenId);
            }
            if (_quantity > numOwned){
                revert InvalidIntValue("INV_QTY", _quantity, numOwned);
            }
            if (!assetContract.isApprovedForAll(_addressToCheck, address(this))) {
                revert ApprovalNotSetForMarketplace();
            }
        } else {
            revert("UNSUPPORTED_ERC_STANDARD");
        }
    }

    /**
     * @dev Internal function to create a listing.
     * @param _listing The listing structure containing listing details.
     */
    function createListing(
        Listing memory _listing
    )
    internal
    {
        // Verify asset can be sold
        verifyAssetCanBeSold(_listing.listingAddress, _listing.seller, _listing.tokenId, _listing.numListed);

        // Validate price is not zero
        if (_listing.pricePer == 0) {
            revert CreateListingFailed("INV_PRICE", _listing.listingId, _listing.listingAddress, _listing.seller, _listing.buyer, _listing.tokenId, _listing.numListed, _listing.pricePer, _listing.royaltyBasePoints, _listing.active);
        }

        // Access marketplace layout and check if token is already listed
        ListingType storage listingType = layout().listingTypes[_listing.listingAddress];
        if (!listingType.active){
            revert InactiveListingType(_listing.listingAddress);
        }

        EnumerableSet.UintSet storage supportedERCStandards = layout().supportedERCStandards;
        if (!supportedERCStandards.contains(listingType.ercStandard)){
            revert UnsupportedERCStandard(listingType.ercStandard);
        }

        EnumerableSet.UintSet storage tokensListedForListingAddress = layout().tokensListedByListingAddress[_listing.listingAddress];
        if (tokensListedForListingAddress.contains(_listing.tokenId)){
            revert CreateListingFailed("TOKEN_ALREADY_LISTED", _listing.listingId, _listing.listingAddress, _listing.seller, _listing.buyer, _listing.tokenId, _listing.numListed, _listing.pricePer, _listing.royaltyBasePoints, _listing.active);
        }

        // Add token to the listing and emit event
        tokensListedForListingAddress.add(_listing.tokenId);
        layout().listings[_listing.listingId] = Listing(
            _listing.listingId,
            _listing.listingAddress,
            _listing.seller,
            _listing.buyer,
            _listing.tokenId,
            _listing.numListed,
            _listing.pricePer,
            _listing.royaltyBasePoints,
            _listing.active,
            true
        );
        layout().activeListings.add(_listing.listingId);
    }

    function updateListing(
        Listing memory _listing
    )
    internal
    {
        Listing storage storedListing = layout().listings[_listing.listingId];

        if (!storedListing.valid){
            revert InvalidListing(_listing.listingId);
        }

        layout().listings[_listing.listingId] = _listing;
    }

    function transferTokens(
        address _contractAddress,
        address _from,
        address _to,
        uint256 _tokenId,
        uint256 _quantity
    )
    internal
    {
        // Transfer the token to the buyer
        ListingType storage listingType = layout().listingTypes[_contractAddress];
        if (listingType.ercStandard == 721){
            ERC721Base assetContract = ERC721Base(listingType.contractAddress);
            assetContract.safeTransferFrom(_from, _to, _tokenId);
        } else if (listingType.ercStandard == 1155){
            ERC1155Base assetContract = ERC1155Base(listingType.contractAddress);
            assetContract.safeTransferFrom(_from, _to, _tokenId, _quantity, "");
        } else {
            revert("UNSUPPORTED_ERC_STANDARD");
        }
    }
}

contracts/facets/minting/SilksMinterAdmi.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.23;

import {SilksMinterStorage} from "./SilksMinterStorage.sol";
import {EnumerableSet} from "@solidstate/contracts/data/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";
import {IAvatarNFT} from "../../interfaces/IAvatarNFT.sol";
import {AccessControlInternal} from "@solidstate/contracts/access/access_control/AccessControlInternal.sol";
import {MINTER_ADMIN_ROLE} from "../../utils/constants.sol";
import {CONTRACT_ADMIN_ROLE} from "../../SilksMarketplaceStorage.sol";

contract SilksMinterAdminFacet is AccessControlInternal {
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;
    using SilksMinterStorage for SilksMinterStorage.Layout;

    // Custom errors
    error InvalidDiscountIndex();
    error DiscountMustBeGreaterThanZero();
    error InvalidDiscountDuration();
    error InvalidAvatarIdRange();
    error DiscountAvatarIdRangeOverlap();

    function addUsedAvatarTokenId(
        uint256 tokenId,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        usedAvatarTokens.add(tokenId);
    }

    function addUsedAvatarTokenIds(
        uint256[] calldata tokenIds,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        uint256 i;
        uint256 tokenIdLength = tokenIds.length;
        for (; i < tokenIdLength; ) {
            usedAvatarTokens.add(tokenIds[i]);

            unchecked {
                ++i;
            }
        }
    }

    function removeUsedAvatarTokenId(
        uint256 tokenId,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        usedAvatarTokens.remove(tokenId);
    }

    function removeUsedAvatarTokenIds(
        uint256[] calldata tokenIds,
        uint256 seasonId,
        uint256 discountIndex
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        EnumerableSet.UintSet storage usedAvatarTokens = SilksMinterStorage
        .layout()
        .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;

        uint256 i;
        uint256 tokenIdLength = tokenIds.length;
        for (; i < tokenIdLength; ) {
            usedAvatarTokens.remove(tokenIds[i]);

            unchecked {
                ++i;
            }
        }
    }

    function updateDiscount(
        uint256 discountIndex,
        uint256 newDiscountPercentage,
        uint256 newDiscountStartDate,
        uint256 newDiscountExpiration,
        uint256 avatarStartId,
        uint256 avatarEndId,
        uint256 seasonId
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        if (discountIndex >= l.seasonIdToDiscounts[seasonId].length)
            revert InvalidDiscountIndex();

        SilksMinterStorage.Discount storage discount = l.seasonIdToDiscounts[
            seasonId
        ][discountIndex];

        discount.discount = newDiscountPercentage;
        discount.discountStartDate = newDiscountStartDate;
        discount.discountExpiration = newDiscountExpiration;
        discount.avatarStartId = avatarStartId;
        discount.avatarEndId = avatarEndId;
    }

    function removeDiscount(
        uint256 discountIndex,
        uint256 seasonId
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        if (discountIndex >= l.seasonIdToDiscounts[seasonId].length)
            revert InvalidDiscountIndex();

        uint256 lastIndex = l.seasonIdToDiscounts[seasonId].length - 1;
        if (discountIndex != lastIndex) {
            if (discountIndex != lastIndex) {
                // Copy the last element to the index to be removed
                uint256 seasonLength = l.seasonIdToDiscounts[seasonId].length;

                l.seasonIdToDiscounts[seasonId][discountIndex].discount = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].discount;

                l
                .seasonIdToDiscounts[seasonId][discountIndex]
                    .discountStartDate = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .discountStartDate;

                l
                .seasonIdToDiscounts[seasonId][discountIndex]
                    .discountExpiration = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .discountExpiration;

                l.seasonIdToDiscounts[seasonId][discountIndex].avatarStartId = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].avatarStartId;

                l.seasonIdToDiscounts[seasonId][discountIndex].avatarEndId = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1].avatarEndId;

                EnumerableSet.UintSet storage idsToRemove = l
                .seasonIdToDiscounts[seasonId][discountIndex].usedAvatarTokens;
                EnumerableSet.UintSet storage idsToReplaceIt = l
                .seasonIdToDiscounts[seasonId][seasonLength - 1]
                    .usedAvatarTokens;

                // Remove all from idsToRemove
                uint256 i;
                uint256 idsToRemoveLength = idsToRemove.length();
                for (; i < idsToRemoveLength; ) {
                    idsToRemove.remove(idsToRemove.at(i));

                    unchecked {
                        ++i;
                    }
                }

                // Add all from idsToReplaceIt
                i = 0;
                for (; i < idsToRemoveLength; ) {
                    idsToRemove.add(idsToReplaceIt.at(i));

                    unchecked {
                        ++i;
                    }
                }
            }
        }
        l.seasonIdToDiscounts[seasonId].pop();
    }

   function addDiscount(
    uint256 discountPercentage,
    uint256 discountStartDate,
    uint256 discountExpiration,
    uint256 avatarStartId,
    uint256 avatarEndId,
    uint256 seasonId
) external onlyRole(MINTER_ADMIN_ROLE) {
    if (discountPercentage == 0) revert DiscountMustBeGreaterThanZero();
    if (discountExpiration <= discountStartDate)
        revert InvalidDiscountDuration();
    if (avatarEndId < avatarStartId)
        revert InvalidAvatarIdRange();

    SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

    // Check for avatarId range overlap with existing discounts for the same season
    uint256 length = l.seasonIdToDiscounts[seasonId].length;
    for (uint256 i = 0; i < length; i++) {
        SilksMinterStorage.Discount storage existingDiscount = l.seasonIdToDiscounts[seasonId][i];
        // Check for overlapping avatarId regardless of the discount date range
        bool isOverlappingAvatarId = avatarStartId <= existingDiscount.avatarEndId && avatarEndId >= existingDiscount.avatarStartId;
        if (isOverlappingAvatarId) {
            // If avatarId ranges overlap, revert regardless of the date overlap            
            revert DiscountAvatarIdRangeOverlap();
        }
    }

        // Push the new Discount to the storage array
        SilksMinterStorage.Discount storage newDiscount = l
            .seasonIdToDiscounts[seasonId]
            .push();
        // Assign the values to the new Discount
        newDiscount.discount = discountPercentage;
        newDiscount.discountStartDate = discountStartDate;
        newDiscount.discountExpiration = discountExpiration;
        newDiscount.avatarStartId = avatarStartId;
        newDiscount.avatarEndId = avatarEndId;
    }

    // Add a new contract with its mint function
    function addContract(
        address contractAddress,
        string calldata mintFunctionSignature,
        ContractType contractType
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().addContract(
            contractAddress,
            mintFunctionSignature,
            contractType
        );
    }

    // Remove a contract
    function removeContract(
        address contractAddres
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().removeContract(contractAddres);
    }

    // Update a contract
    function updateContract(
        address oldAddress,
        address newAddress,
        string calldata mintFunctionSignature,
        ContractType newContractType
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().updateContract(
            oldAddress,
            newAddress,
            mintFunctionSignature,
            newContractType
        );
    }

    function updateMintExclusion(
        bool enable,
        uint256 startTime,
        uint256 endTime
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        l.mintingExclusiveToAvatarHolders = enable;
        l.mintingExclusionStartDateTime = startTime;
        l.mintingExclusionEndDateTime = endTime;
    }

    function updateAvatarAddress(
        address newAvatarAddress
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        SilksMinterStorage.layout().avatarAddress = newAvatarAddress;
    }

    function grantMinterAdminRole(
        address newAdmin
    ) external onlyRole(CONTRACT_ADMIN_ROLE) {
        _grantRole(MINTER_ADMIN_ROLE, newAdmin);
    }

    function revokeMinterAdminRole(
        address admin
    ) external onlyRole(CONTRACT_ADMIN_ROLE) {
        _revokeRole(MINTER_ADMIN_ROLE, admin);
    }

    // AvatarProxy Functions
    // Transfer AvatarOwnership
    function setAvatarSaleInformation(
        uint256 publicSaleTime,
        uint256 preSaleTime,
        uint256 maxPerAddress,
        uint256 presaleMaxPerAddress,
        uint256 price,
        uint256 presalePrice,
        bytes32 merkleRoot,
        uint256 maxTxPerAddress
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress)
            .setSaleInformation(
                publicSaleTime,
                preSaleTime,
                maxPerAddress,
                presaleMaxPerAddress,
                price,
                presalePrice,
                merkleRoot,
                maxTxPerAddress
            );
    }

    // Set the base URI for the Avatar NFT metadata
    function setAvatarBaseUri(
        string memory baseUri
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).setBaseUri(
            baseUri
        );
    }

    // Set the Merkle root for the presale whitelist
    function setAvatarMerkleRoot(
        bytes32 merkleRoot
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).setMerkleRoot(
            merkleRoot
        );
    }

    // Pause the Avatar NFT minting process
    function pauseAvatarMinting() external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).pause();
    }

    // Unpause the Avatar NFT minting process
    function unpauseAvatarMinting() external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).unpause();
    }

    // Transfer the ownership of the Avatar NFT contract
    function transferAvatarOwnership(
        address newOwner
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        IAvatarNFT(SilksMinterStorage.layout().avatarAddress).transferOwnership(
                newOwner
            );
    }
}

contracts/facets/minting/SilksMinterFace.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.23;

import {SilksMinterStorage} from "./SilksMinterStorage.sol";
import {EnumerableSet} from "@solidstate/contracts/data/EnumerableSet.sol";
import {ContractType} from "../../utils/constants.sol";
import {IERC721Mintable} from "../../interfaces/IERC721Mintable.sol";
import {IAvatarNFT} from "../../interfaces/IAvatarNFT.sol";
import {IHorseNFT} from "../../interfaces/IHorseNFT.sol";
import {AccessControlInternal} from "@solidstate/contracts/access/access_control/AccessControlInternal.sol";
import {MINTER_ADMIN_ROLE} from "../../utils/constants.sol";

contract SilksMinterFacet is AccessControlInternal {
    // using EnumerableMap for EnumerableMap.UintToAddressMap;
    using EnumerableSet for EnumerableSet.AddressSet;
    using EnumerableSet for EnumerableSet.UintSet;
    using SilksMinterStorage for SilksMinterStorage.Layout;

    event Minted(
        address contractAddress,
        address indexed to,
        uint256 quantity,
        uint256 value
    );

    event Airdropped(
        address contractAddress,
        address indexed to,
        uint256 quantity
    );

    struct MintParams {
        uint256 seasonId; // For Horse
        uint256 payoutTier; // For Horse
        uint256 quantity; // Common parameter
        address to; // Common parameter
    }

    // Same as above but return a struct with the avatarId and the discount
    struct AvatarDiscount {
        uint256 avatarId;
        int256 discountIndex;
        uint256 discountPercentage;
    }

    error MintExlusiveToAvatarHolders();
    error InsufficientFunds(uint256 _required, uint256 _sent);
    error MintingFailed(bytes data);
    error IncorrectAvatarOwner(
        uint256 _avatarId,
        address _owner,
        address _sender
    );
    error DiscountNotFound(uint256 _discountIndex);
    error AvatarNotEligibleForDiscount(uint256 _avatarId, uint256 _seasonId);

    /**
     * @notice Modifier to check if HorseV2 minting is exclusive to Avatar holders
     * @param contractAddress The address of the contract that tokens are being
     * minted for
     */
    modifier checkMintingExclusiveToAvatarHolders(address contractAddress) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        // If the contractAddress is for contractType.HorseV2, then we need to
        // check if the minting is exclusive to Avatar holders
        if (l.mintingExclusiveToAvatarHolders) {
            if (
                l.getContract(contractAddress).contractType ==
                ContractType.HorseV2
            ) {
                if (
                    block.timestamp >= l.mintingExclusionStartDateTime &&
                    block.timestamp <= l.mintingExclusionEndDateTime
                ) {
                    if (
                        IAvatarNFT(l.avatarAddress).balanceOf(msg.sender) == 0
                    ) {
                        revert MintExlusiveToAvatarHolders();
                    }
                }
            }
        }

        _;
    }

    /**
     * @notice External function to mint tokens to the specified address
     * @dev This is the main function for web3 minting to purchase and mint tokens.
     * @param contractAddress The address of the contract to mint tokens to
     * @param params The minting parameters
     * @param additionalPayload The additional payload to be used for minting
     * @param avatarIds The avatarIds to be added to the usedAvatarTokens list
     */
    function mint(
        address contractAddress,
        MintParams memory params,
        bytes memory additionalPayload,
        uint256[] calldata avatarIds
    ) external payable checkMintingExclusiveToAvatarHolders(contractAddress) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        SilksMinterStorage.ContractData memory contractData = l.getContract(
            contractAddress
        );
        IERC721Mintable tokenContract = IERC721Mintable(
            contractData.contractAddress
        );
        IAvatarNFT avatarContract = IAvatarNFT(l.avatarAddress);

        mintTokens(contractAddress, params, additionalPayload);

        // Calculate price and check if the user has sent enough value
        uint256 requiredValue;
        uint256 pricePerToken;
        if (contractData.contractType == ContractType.HorseV2) {
            (, , pricePerToken, , , , , ) = IHorseNFT(
                contractData.contractAddress
            ).payoutTier(params.payoutTier);
            requiredValue = pricePerToken * params.quantity;
        } else {
            pricePerToken = tokenContract._price();
            requiredValue = pricePerToken * params.quantity;
        }

        if (contractData.contractType == ContractType.HorseV2) {
            uint256 totalDiscount = calculateDiscount(
                avatarIds,
                pricePerToken,
                avatarContract,
                params.quantity,
                params.seasonId
            );

            requiredValue -= totalDiscount;
        }

        // Emit an event with mint details
        emit Minted(contractAddress, params.to, params.quantity, requiredValue);

        if (msg.value < requiredValue) {
            revert InsufficientFunds(requiredValue, msg.value);
        }

        // Refund excess value
        if (msg.value > requiredValue) {
            // console.log("Refunding excess value: ", msg.value - requiredValue);
            payable(msg.sender).transfer(msg.value - requiredValue);
        }
    }

    /**
     * Airdrops tokens to the specified address and adds the avatarIds to the usedAvatarTokens list
     * @param contractAddress The address of the contract to airdrop tokens to
     * @param params The minting parameters
     * @param additionalPayload The additional payload to be used for minting
     */
    function airdrop(
        address contractAddress,
        MintParams memory params,
        bytes memory additionalPayload
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        mintTokens(contractAddress, params, additionalPayload);

        emit Airdropped(contractAddress, params.to, params.quantity);
    }

    /**
     * Airdrops tokens to the specified address and adds the avatarIds to the usedAvatarTokens list
     * @param contractAddress The address of the contract to airdrop tokens to
     * @param params The minting parameters
     * @param additionalPayload The additional payload to be used for minting
     * @param avatarIds The avatarIds to be added to the usedAvatarTokens list
     */
    function airdrop(
        address contractAddress,
        MintParams memory params,
        bytes memory additionalPayload,
        uint256[] calldata avatarIds
    ) external onlyRole(MINTER_ADMIN_ROLE) {
        mintTokens(contractAddress, params, additionalPayload);

        emit Airdropped(contractAddress, params.to, params.quantity);

        uint256 i;
        uint256 tokenIdLength = avatarIds.length;
        for (; i < tokenIdLength; ) {
            int256 discountIndex = getDiscountIndexForAvatar(
                avatarIds[i],
                params.seasonId
            );

            if (discountIndex == -1) {
                revert AvatarNotEligibleForDiscount(
                    avatarIds[i],
                    params.seasonId
                );
            }

            SilksMinterStorage
                .layout()
                .seasonIdToDiscounts[params.seasonId][uint256(discountIndex)]
                .usedAvatarTokens
                .add(avatarIds[i]);

            unchecked {
                ++i;
            }
        }
    }

    /**
     *  Mint tokens to the specified address
     * @param contractAddress  The address of the contract to mint tokens to
     * @param params The minting parameters
     * @param additionalPayload  The additional payload to be used for minting
     */
    function mintTokens(
        address contractAddress,
        MintParams memory params,
        bytes memory additionalPayload
    ) internal {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();
        SilksMinterStorage.ContractData memory contractData = l.getContract(
            contractAddress
        );

        IERC721Mintable tokenContract = IERC721Mintable(
            contractData.contractAddress
        );

        if (contractData.contractType == ContractType.HorseV2) {
            IHorseNFT(contractData.contractAddress).externalMint(
                params.seasonId,
                params.payoutTier,
                params.quantity,
                params.to
            );
        } else if (contractData.contractType == ContractType.Avatar) {
            IAvatarNFT(contractData.contractAddress).mint(
                params.to,
                params.quantity
            );
        } else {
            (bool success, bytes memory data) = address(tokenContract).call(
                additionalPayload
            );
            if (!success) {
                revert MintingFailed(data);
            }
        }
    }

    function calculateDiscount(
        uint256[] calldata avatarIds,
        uint256 pricePerToken,
        IAvatarNFT avatarContract,
        uint256 maxDiscounts,
        uint256 seasonId
    ) internal returns (uint256 totalDiscount) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256 appliedDiscounts;
        uint256 i;
        uint256 avatarsLength = avatarIds.length;
        for (; i < avatarsLength; ) {
            if (appliedDiscounts >= maxDiscounts) {
                break;
            }

            uint256 avatarId = avatarIds[i];
            uint256 j = 0;
            uint256 discountLength = l.seasonIdToDiscounts[seasonId].length;
            for (; j < discountLength; ) {
                SilksMinterStorage.Discount storage discount = l
                    .seasonIdToDiscounts[seasonId][j];

                if (
                    block.timestamp >= discount.discountStartDate &&
                    block.timestamp <= discount.discountExpiration &&
                    avatarId >= discount.avatarStartId &&
                    avatarId <= discount.avatarEndId &&
                    !discount.usedAvatarTokens.contains(avatarId)
                ) {
                    if (avatarContract.ownerOf(avatarId) != msg.sender) {
                        revert IncorrectAvatarOwner(
                            avatarId,
                            avatarContract.ownerOf(avatarId),
                            msg.sender
                        );
                    }

                    totalDiscount += (pricePerToken * discount.discount) / 100;
                    appliedDiscounts++;

                    discount.usedAvatarTokens.add(avatarId);

                    break;
                }

                unchecked {
                    ++j;
                }
            }

            unchecked {
                ++i;
            }
        }
    }

    /**
     * Check if an avatar is eligible for a discount
     * @param avatarId  The avatar ID to check for discount
     * @param seasonId  The season ID to check for discount
     */
    function isAvatarEligibleForDiscount(
        uint256 avatarId,
        uint256 seasonId
    ) public view returns (bool) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256[] memory currentDiscounts = getActiveDiscountIds(seasonId);

        uint256 i;
        uint256 currentDiscountsLength = currentDiscounts.length;
        for (; i < currentDiscountsLength; ) {
            SilksMinterStorage.Discount storage discount = l
                .seasonIdToDiscounts[seasonId][currentDiscounts[i]];

            if (
                avatarId >= discount.avatarStartId &&
                avatarId <= discount.avatarEndId &&
                !discount.usedAvatarTokens.contains(avatarId)
            ) {
                return true;
            }

            unchecked {
                ++i;
            }
        }
        return false;
    }

    /**
     * Get the count of active discounts for a given seasonId
     * @param seasonId The season ID to check for active discounts
     * @return currentDiscountsCount uint256 The count of active discounts
     */
    function getActiveDiscountCount(
        uint256 seasonId
    ) public view returns (uint256 currentDiscountsCount) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256 i;
        uint256 discountLength = l.seasonIdToDiscounts[seasonId].length;
        for (; i < discountLength; ) {
            SilksMinterStorage.Discount storage discount = l
                .seasonIdToDiscounts[seasonId][i];

            if (
                block.timestamp >= discount.discountStartDate &&
                block.timestamp <= discount.discountExpiration
            ) {
                currentDiscountsCount++;
            }

            unchecked {
                ++i;
            }
        }

        return currentDiscountsCount;
    }

    /**
     * @notice Returns the discount IDs that are currently active for a given seasonId
     * @param seasonId The season ID to check for active discounts
     * @return currentDiscounts uint256[] The active discount IDs
     */
    function getActiveDiscountIds(
        uint256 seasonId
    ) public view returns (uint256[] memory currentDiscounts) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256 count = getActiveDiscountCount(seasonId);
        uint256[] memory activeDiscounts = new uint256[](count);

        uint256 activeDiscountTrackerIndex = 0;
        uint256 i;
        uint256 discountLength = l.seasonIdToDiscounts[seasonId].length;
        for (; i < discountLength; ) {
            SilksMinterStorage.Discount storage discount = l
                .seasonIdToDiscounts[seasonId][i];

            if (
                block.timestamp >= discount.discountStartDate &&
                block.timestamp <= discount.discountExpiration
            ) {
                activeDiscounts[activeDiscountTrackerIndex] = i;
                activeDiscountTrackerIndex++;
            }

            unchecked {
                ++i;
            }
        }
        return activeDiscounts;
    }

    /**
     * @notice Get the contract data for a given contract address
     * @param _contractAddress The address of the contract to get ContractData for
     * @return contractData SilksMinterStorage.ContractData The ContractData for the given contractAddress
     */
    function getContract(
        address _contractAddress
    )
        external
        view
        returns (SilksMinterStorage.ContractData memory contractData)
    {
        return SilksMinterStorage.layout().getContract(_contractAddress);
    }

    /**
     * @notice Return all contract data currently on the marketplace
     * @return contractData SilksMinterStorage.ContractData[] The ContractData for all contracts on the marketplace
     */
    function getContracts()
        public
        view
        returns (SilksMinterStorage.ContractData[] memory contractData)
    {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256 count = l.addresses.length();
        uint256 i;
        for (; i < count; ) {
            contractData[i] = l.getContract(l.addresses.at(i));

            unchecked {
                ++i;
            }
        }
    }

    /**
     * @notice Get the discount data for a given discount index and seasonId
     * @param discountIndex The index of the discount to get data for
     * @param seasonId The season ID to get discount data for
     * @return discountPercentage The discount percentage
     * @return discountStartDate Unix timestamp for the start date of the discount
     * @return discountExpiration Unix timestamp for the expiration date of the discount
     * @return usedAvatarTokens Array of avatar tokens that have used the discount
     * @return avatarStartId Start ID of the AvatarNFT's range for this discount
     * @return avatarEndId End ID of the AvatarNFT's range for this discount
     */
    function getDiscount(
        uint256 discountIndex,
        uint256 seasonId
    )
        public
        view
        returns (
            uint256 discountPercentage,
            uint256 discountStartDate,
            uint256 discountExpiration,
            uint256[] memory usedAvatarTokens, // Using EnumerableSet for efficient tracking
            uint256 avatarStartId, // Start ID of the AvatarNFT's range for this discount
            uint256 avatarEndId // End ID of the AvatarNFT's range for this discount
        )
    {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        if (l.seasonIdToDiscounts[seasonId].length <= discountIndex) {
            revert DiscountNotFound(discountIndex);
        }

        SilksMinterStorage.Discount storage discountData = SilksMinterStorage
            .layout()
            .seasonIdToDiscounts[seasonId][discountIndex];

        discountPercentage = discountData.discount;
        discountStartDate = discountData.discountStartDate;
        discountExpiration = discountData.discountExpiration;
        avatarStartId = discountData.avatarStartId;
        avatarEndId = discountData.avatarEndId;
        usedAvatarTokens = discountData.usedAvatarTokens.toArray();

        return (
            discountPercentage,
            discountStartDate,
            discountExpiration,
            usedAvatarTokens,
            avatarStartId,
            avatarEndId
        );
    }

    /**
     * @notice Get the address for the Avatar contract on this chain.
     */
    function getAvatarAddress() public view returns (address) {
        return SilksMinterStorage.layout().avatarAddress;
    }

    /**
     * Given an array of avatarIds and a seasonId, return the avatars that are eligible for a discount
     * @param avatarIds Array of avatarIds to check for discount
     * @param seasonId Season ID to check for discount
     */
    function getEligibleAvatarsForDiscount(
        uint256[] calldata avatarIds,
        uint256 seasonId
    ) public view returns (uint256[] memory eligibleAvatars) {
        uint256 avatarLength = avatarIds.length;
        uint256 eligibleAvatarTrackerIndex;
        uint256 i;
        for (; i < avatarLength; ) {
            if (isAvatarEligibleForDiscount(avatarIds[i], seasonId)) {
                eligibleAvatars[eligibleAvatarTrackerIndex] = avatarIds[i];
                eligibleAvatarTrackerIndex++;
            }

            unchecked {
                ++i;
            }
        }

        return eligibleAvatars;
    }

    /**
     * Given an avatarId and a seasonId, return the discount index for the avatar.
     * @param avatarId Avatar ID to check for discount
     * @param seasonId  Season ID to check for discount
     * @return uint256 The discount index for the avatar
     */
    function getDiscountIndexForAvatar(
        uint256 avatarId,
        uint256 seasonId
    ) private view returns (int256) {
        SilksMinterStorage.Layout storage l = SilksMinterStorage.layout();

        uint256[] memory currentDiscounts = getActiveDiscountIds(seasonId);

        uint256 i;
        uint256 currentDiscountsLength = currentDiscounts.length;
        for (; i < currentDiscountsLength; ) {
            SilksMinterStorage.Discount storage discount = l
                .seasonIdToDiscounts[seasonId][currentDiscounts[i]];

            if (
                avatarId >= discount.avatarStartId &&
                avatarId <= discount.avatarEndId &&
                !discount.usedAvatarTokens.contains(avatarId)
            ) {
                return int256(discount.discount);
            }

            unchecked {
                ++i;
            }
        }
        return -1;
    }

    /**
     * Given an array of avatarIds and a seaosonId, return the avatars that are eligible for a discount
     * and the discountIndex for the given avatarId.
     * @param avatarIds Array of avatarIds to check for discount
     * @param seasonId Season ID to check for discount
     * @return AvatarDiscount[] Array of eligible avatars and their discountIndexes
     */
    function getDiscountsForAvatars(
        uint256[] calldata avatarIds,
        uint256 seasonId
    ) public view returns (AvatarDiscount[] memory) {
        uint256 i;
        uint256 avatarLength = avatarIds.length;
        uint256 eligibleAvatarCount;
        uint256[] memory eligibleAvatars = new uint256[](avatarLength);
        for (; i < avatarLength; ) {
            if (isAvatarEligibleForDiscount(avatarIds[i], seasonId)) {
                eligibleAvatars[eligibleAvatarCount] = avatarIds[i];
                eligibleAvatarCount++;
            }

            unchecked {
                ++i;
            }
        }

        AvatarDiscount[] memory eligibleAvatarsDiscounts = new AvatarDiscount[](
            eligibleAvatarCount
        );
        uint256 j;
        uint256 eligibleAvatarTrackerIndex;
        for (; j < eligibleAvatarCount; ) {
            eligibleAvatarsDiscounts[eligibleAvatarTrackerIndex]
                .avatarId = eligibleAvatars[j];
            eligibleAvatarsDiscounts[eligibleAvatarTrackerIndex]
                .discountIndex = getDiscountIndexForAvatar(
                eligibleAvatars[j],
                seasonId
            );

            eligibleAvatarTrackerIndex++;
            unchecked {
                ++j;
            }
        }

        return eligibleAvatarsDiscounts;
    }
}

